const newsContainer=document.getElementById("news-container");fetch("/api/news",{method:"GET"}).then(e=>{e.json().then(e=>{e.data.forEach(e=>{var t=document.createElement("li"),n=document.createElement("a"),a=document.createElement("h6");n.href=`/news/${e.id}`,n.innerText=e.title,a.textContent=`(${moment.utc(e.created_at).fromNow()})`,twemoji.parse(n),t.appendChild(n),t.appendChild(a),newsContainer.appendChild(t)})})});